import {createModuleGraph} from '@thepassle/module-graph';
import glob from 'glob';
// import {exportToFile} from '@ts-graphviz/node';

// node gen-module-graph.js | pbcopy
// paste to https://graphviz.corp.google.com/#977cbf331bcf57e66965e8d834c71441

// see https://github.com/thepassle/module-graph

const auditFiles = glob.sync('./core/audits/**/*.js');

const digraphPlugin = {
  name: 'digraph-plugin',
  end(moduleGraph) {
    let digraph = 'digraph {\n';
    digraph += `
rankdir="LR"

fontname="Helvetica,Arial,sans-serif"
node [fontname="Helvetica,Arial,sans-serif"]
edge [fontname="Helvetica,Arial,sans-serif"]
node [fontsize=10, shape=box, height=0.25]
edge [fontsize=10]

`;
    for (const [parent, importees] of moduleGraph.graph) {
      const importeesStr = [...importees].map(i => `"${i}"`);
      digraph += `  "${parent}" -> ${importeesStr.join(',')}\n`;
    }
    digraph += '}';

    moduleGraph.digraph = digraph;
  },
};

const moduleGraph = await createModuleGraph(auditFiles, {
  plugins: [digraphPlugin],
  /** Handle external modules */
  external: {
    /** Ignore all external modules imported via a bare module specifier */
    ignore: true,
    // /** Only include external modules from these packages */
    // include: ['bar'],
    /** Exclude bare module specifiers */
    exclude: ['foo', '@foo/bar'],
  },

  /** Picomatch glob pattern or callback */
  exclude: [
    '**/localization/**',
    '**/i18n/**',
    // (importee) => importee.includes('foo')
  ],

});

console.log(moduleGraph.digraph);
